+    #[test]
+    fn sm36_stage_summary_all_stages(_dummy in 0u8..1) {
+        let timeline = ResizeTimeline {
+            scenario: "test".to_string(),
+            reproducibility_key: "test:v1:test:0".to_string(),
+            captured_at_ms: 1000,
+            executed_resize_events: 0,
